import time
import random
import string
import threading
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import urlparse, parse_qs

from prometheus_client import (
    Counter,
    Histogram,
    Gauge,
    generate_latest,
    REGISTRY,
    CONTENT_TYPE_LATEST,
    CollectorRegistry,
)


# Global metrics
REQUEST_COUNT = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['user_id', 'session_id', 'path', 'method', 'status_code']
)

REQUEST_DURATION = Histogram(
    'http_request_duration_seconds',
    'HTTP request duration in seconds',
    ['user_id', 'session_id', 'path', 'method'],
    buckets=(0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1.0, 2.5, 5.0, 10.0)
)

ACTIVE_REQUESTS = Gauge(
    'http_active_requests',
    'Number of active HTTP requests',
    ['user_id', 'session_id', 'path']
)

# Per user-path combination metrics tracking
USER_PATH_REQUEST_COUNT = Counter(
    'user_path_requests_total',
    'Total requests per unique user-path combination',
    ['user_id', 'path']
)

USER_PATH_LAST_ACCESS = Gauge(
    'user_path_last_access_timestamp',
    'Last access timestamp for each user-path combination',
    ['user_id', 'path']
)

USER_PATH_SESSION_COUNT = Gauge(
    'user_path_unique_sessions',
    'Number of unique sessions per user-path combination',
    ['user_id', 'path']
)

# In-memory tracker for unique user-path combinations
class TrafficAnalyzer:
    def __init__(self):
        self.lock = threading.Lock()
        # {(user_id, path): set(session_ids)}
        self.user_path_sessions = {}
        # {(user_id, path): count}
        self.user_path_counts = {}
        # {(user_id, path): last_timestamp}
        self.user_path_last_access = {}

    def record_request(self, user_id, session_id, path, method, status_code, duration):
        with self.lock:
            key = (user_id, path)

            # Track sessions per user-path
            if key not in self.user_path_sessions:
                self.user_path_sessions[key] = set()
            self.user_path_sessions[key].add(session_id)

            # Track count
            self.user_path_counts[key] = self.user_path_counts.get(key, 0) + 1

            # Track last access
            self.user_path_last_access[key] = time.time()

        # Update Prometheus metrics
        REQUEST_COUNT.labels(
            user_id=user_id,
            session_id=session_id,
            path=path,
            method=method,
            status_code=str(status_code)
        ).inc()

        REQUEST_DURATION.labels(
            user_id=user_id,
            session_id=session_id,
            path=path,
            method=method
        ).observe(duration)

        USER_PATH_REQUEST_COUNT.labels(
            user_id=user_id,
            path=path
        ).inc()

        USER_PATH_LAST_ACCESS.labels(
            user_id=user_id,
            path=path
        ).set(time.time())

        with self.lock:
            USER_PATH_SESSION_COUNT.labels(
                user_id=user_id,
                path=path
            ).set(len(self.user_path_sessions[key]))

    def get_summary(self):
        with self.lock:
            summary = {}
            for key, count in self.user_path_counts.items():
                user_id, path = key
                summary[key] = {
                    'user_id': user_id,
                    'path': path,
                    'total_requests': count,
                    'unique_sessions': len(self.user_path_sessions.get(key, set())),
                    'last_access': self.user_path_last_access.get(key, 0),
                }
            return summary


# Global analyzer instance
analyzer = TrafficAnalyzer()


class MetricsHandler(BaseHTTPRequestHandler):
    """HTTP handler that tracks requests and serves metrics."""

    def _extract_user_info(self):
        """Extract user_id and session_id from query params or headers."""
        parsed = urlparse(self.path)
        query_params = parse_qs(parsed.query)

        user_id = query_params.get('user_id', [self.headers.get('X-User-ID', 'anonymous')])[0]
        session_id = query_params.get('session_id', [self.headers.get('X-Session-ID', 'unknown')])[0]
        clean_path = parsed.path

        return user_id, session_id, clean_path

    def _handle_request(self, method):
        user_id, session_id, clean_path = self._extract_user_info()

        # Serve metrics endpoint
        if clean_path == '/metrics':
            self._serve_metrics()
            return

        # Serve summary endpoint
        if clean_path == '/summary':
            self._serve_summary()
            return

        # Track the request
        ACTIVE_REQUESTS.labels(
            user_id=user_id,
            session_id=session_id,
            path=clean_path
        ).inc()

        start_time = time.time()

        try:
            # Simulate some processing
            time.sleep(random.uniform(0.001, 0.05))

            status_code = 200
            response_body = (
                f'{{"message": "OK", "user_id": "{user_id}", '
                f'"session_id": "{session_id}", "path": "{clean_path}", '
                f'"method": "{method}"}}'
            ).encode('utf-8')

            self.send_response(status_code)
            self.send_header('Content-Type', 'application/json')
            self.send_header('Content-Length', str(len(response_body)))
            self.end_headers()
            self.wfile.write(response_body)

        except Exception as e:
            status_code = 500
            response_body = f'{{"error": "{str(e)}"}}'.encode('utf-8')
            self.send_response(status_code)
            self.send_header('Content-Type', 'application/json')
            self.end_headers()
            self.wfile.write(response_body)

        finally:
            duration = time.time() - start_time
            ACTIVE_REQUESTS.labels(
                user_id=user_id,
                session_id=session_id,
                path=clean_path
            ).dec()

            analyzer.record_request(
                user_id=user_id,
                session_id=session_id,
                path=clean_path,
                method=method,
                status_code=status_code,
                duration=duration
            )

    def _serve_metrics(self):
        """Serve Prometheus metrics."""
        metrics_output = generate_latest(REGISTRY)
        self.send_response(200)
        self.send_header('Content-Type', CONTENT_TYPE_LATEST)
        self.send_header('Content-Length', str(len(metrics_output)))
        self.end_headers()
        self.wfile.write(metrics_output)

    def _serve_summary(self):
        """Serve traffic analysis summary."""
        import json
        summary = analyzer.get_summary()
        formatted = []
        for key, data in summary.items():
            formatted.append({
                'user_id': data['user_id'],
                'path': data['path'],
                'total_requests': data['total_requests'],
                'unique_sessions': data['unique_sessions'],
                'last_access': data['last_access'],
            })

        # Sort by total requests descending
        formatted.sort(key=lambda x: x['total_requests'], reverse=True)

        response_body = json.dumps({
            'total_unique_combinations': len(formatted),
            'combinations': formatted
        }, indent=2).encode('utf-8')

        self.send_response(200)
        self.send_header('Content-Type', 'application/json')
        self.send_header('Content-Length', str(len(response_body)))
        self.end_headers()
        self.wfile.write(response_body)

    def do_GET(self):
        self._handle_request('GET')

    def do_POST(self):
        self._handle_request('POST')

    def do_PUT(self):
        self._handle_request('PUT')

    def do_DELETE(self):
        self._handle_request('DELETE')

    def do_PATCH(self):
        self._handle_request('PATCH')

    def log_message(self, format, *args):
        """Override to reduce log noise during simulation."""
        pass


def generate_random_id(length=8):
    return ''.join(random.choices(string.ascii_lowercase + string.digits, k=length))


def simulate_traffic(base_url='http://localhost:8080', num_requests=100):
    """Simulate traffic from multiple users hitting various paths."""
    import urllib.request

    users = [f'user_{i}' for i in range(1, 6)]
    sessions = {user: [generate_random_id() for _ in range(random.randint(1, 3))] for user in users}
    paths = [
        '/api/v1/products',
        '/api/v1/products/123',
        '/api/v1/products/456',
        '/api/v1/cart',
        '/api/v1/cart/checkout',
        '/api/v1/users/profile',
        '/api/v1/users/settings',
        '/api/v1/search',
        '/api/v1/orders',
        '/api/v1/orders/789',
        '/dashboard',
        '/dashboard/analytics',
        '/health',
    ]

    print(f"Simulating {num_requests} requests from {len(users)} users...")
    print(f"Users and their sessions:")
    for user, user_sessions in sessions.items():
        print(f"  {user}: {user_sessions}")
    print()

    for i in range(num_requests):
        user = random.choice(users)
        session = random.choice(sessions[user])
        path = random.choice(paths)

        url = f'{base_url}{path}?user_id={user}&session_id={session}'

        try:
            req = urllib.request.Request(url)
            with urllib.request.urlopen(req, timeout=5) as response:
                response.read()
        except Exception as e:
            print(f"Request failed: {e}")

        if (i + 1) % 20 == 0:
            print(f"  Completed {i + 1}/{num_requests} requests")

        time.sleep(random.uniform(0.01, 0.05))

    print(f"\nSimulation complete! {num_requests} requests sent.")
    print(f"\nView metrics at: {base_url}/metrics")
    print(f"View summary at: {base_url}/summary")


def main():
    port = 8080
    server = HTTPServer(('0.0.0.0', port), MetricsHandler)
    print(f"Starting HTTP server on port {port}")
    print(f"Metrics available at: http://localhost:{port}/metrics")
    print(f"Traffic summary at: http://localhost:{port}/summary")
    print()

    # Start server in a thread
    server_thread = threading.Thread(target=server.serve_forever, daemon=True)
    server_thread.start()

    # Wait for server to start
    time.sleep(1)

    # Run traffic simulation
    simulate_traffic(num_requests=100)

    # Print summary
    print("\n" + "=" * 60)
